/* --------------------------------------------------------------------------
 * UART Initialization & Operations (USART1: PA9=TX, PA10=RX)
 * -------------------------------------------------------------------------- */
static void uart_init(void)
{
    /* PA9 AF1 (USART1_TX), PA10 AF1 (USART1_RX) */
    GPIOA->MODER &= ~((3 << (9 * 2)) | (3 << (10 * 2)));
    GPIOA->MODER |= (2 << (9 * 2)) | (2 << (10 * 2));  /* AF mode */
    GPIOA->AFR[1] &= ~((0xF << ((9 - 8) * 4)) | (0xF << ((10 - 8) * 4)));
    GPIOA->AFR[1] |= (1 << ((9 - 8) * 4)) | (1 << ((10 - 8) * 4));  /* AF1 */
    GPIOA->OSPEEDR |= (3 << (9 * 2)) | (3 << (10 * 2));

    /* Configure USART1 */
    USART1->CR1 = 0;  /* Disable */
    USART1->BRR_REG = SYSTEM_CLOCK / UART_BAUD_RATE;
    USART1->CR1 = (1 << 0) | (1 << 2) | (1 << 3);  /* UE, RE, TE */
}

static void uart_send_byte(uint8_t b)
{
    while (!(USART1->ISR & USART_ISR_TXE));
    USART1->TDR = b;
}

static void uart_send_string(const char *str)
{
    while (*str) {
        uart_send_byte((uint8_t)*str++);
    }
}

static bool uart_recv_byte(uint8_t *b, uint32_t timeout_ms)
{
    uint32_t start = get_tick();
    while (!(USART1->ISR & USART_ISR_RXNE)) {
        if ((get_tick() - start) >= timeout_ms) {
            return false;
        }
    }
    *b = (uint8_t)(USART1->RDR & 0xFF);
    return true;
}

static void uart_flush(void)
{
    while (USART1->ISR & USART_ISR_RXNE) {
        (void)USART1->RDR;
    }
}

/* --------------------------------------------------------------------------
 * SPI Initialization & Operations
 * -------------------------------------------------------------------------- */
static void spi_init(void)
{
    /* Reconfigure PA5 (SCK), PA6 (MISO), PA7 (MOSI) for SPI1 AF0 */
    /* PA5 */
    GPIOA->MODER &= ~(3 << (5 * 2));
    GPIOA->MODER |= (2 << (5 * 2));   /* AF mode */
    GPIOA->AFR[0] &= ~(0xF << (5 * 4));
    GPIOA->AFR[0] |= (0 << (5 * 4));  /* AF0 */
    /* PA6 */
    GPIOA->MODER &= ~(3 << (6 * 2));
    GPIOA->MODER |= (2 << (6 * 2));
    GPIOA->AFR[0] &= ~(0xF << (6 * 4));
    GPIOA->AFR[0] |= (0 << (6 * 4));
    /* PA7 */
    GPIOA->MODER &= ~(3 << (7 * 2));
    GPIOA->MODER |= (2 << (7 * 2));
    GPIOA->AFR[0] &= ~(0xF << (7 * 4));
    GPIOA->AFR[0] |= (0 << (7 * 4));

    GPIOA->OSPEEDR |= (3 << (5 * 2)) | (3 << (6 * 2)) | (3 << (7 * 2));

    /* SPI1 config: Master, CPOL=0, CPHA=0, 8-bit, slow clock initially (fPCLK/256) */
    SPI1->CR1 = 0;
    SPI1->CR1 = (1 << 2)       /* MSTR: Master mode */
              | (7 << 3)       /* BR[2:0] = 111: fPCLK/256 for init */
              | (1 << 8)       /* SSI */
              | (1 << 9);      /* SSM: Software slave management */
    SPI1->CR2 = (7 << 8);     /* DS[3:0] = 0111: 8-bit data */
    SPI1->CR2 |= (1 << 12);   /* FRXTH: RXNE on 8-bit */
    SPI1->CR1 |= (1 << 6);    /* SPE: Enable SPI */
}

static void spi_set_fast(void)
{
    SPI1->CR1 &= ~(1 << 6);   /* Disable SPI */
    SPI1->CR1 &= ~(7 << 3);
    SPI1->CR1 |= (1 << 3);    /* BR = 001: fPCLK/4 = 2MHz */
    SPI1->CR1 |= (1 << 6);    /* Enable SPI */
}

static uint8_t spi_transfer(uint8_t data)
{
    while (!(SPI1->SR & (1 << 1)));  /* Wait TXE */
    *(volatile uint8_t *)&SPI1->DR = data;
    while (!(SPI1->SR & (1 << 0)));  /* Wait RXNE */
    return *(volatile uint8_t *)&SPI1->DR;
}

